    ("w", "schemas/mutation-receipt.v1.schema.json", "{\n  \"$schema\": \"https://json-schema.org/draft/2020-12/schema\",\n  \"$id\": \"https://aegisomega.com/schemas/mutation-receipt.v1.schema.json\",\n  \"title\": \"AEGIS MutationReceipt V1\",\n  \"type\": \"object\",\n  \"additionalProperties\": false,\n  \"required\": [\"receipt_version\",\"execution_identity_root\",\"workspace_binding\",\"policy_decision_root\",\"authority_score\",\"authority_domain\",\"action_class\",\"tool\",\"target\",\"pre_state_digest\",\"requested_action_digest\",\"result_digest\",\"post_state_digest\",\"parent_receipt\",\"sequence\",\"outcome\",\"denial_code\"],\n  \"properties\": {\n    \"receipt_version\": {\"const\": \"1.0.0\"},\n    \"execution_identity_root\": {\"$ref\": \"#/$defs/hash\"},\n    \"workspace_binding\": {\"$ref\": \"#/$defs/hash\"},\n    \"policy_decision_root\": {\"$ref\": \"#/$defs/hash\"},\n    \"authority_score\": {\"type\": \"string\", \"pattern\": \"^(0|1)\\\\.[0-9]{6}$\"},\n    \"authority_domain\": {\"type\": \"string\", \"minLength\": 1},\n    \"action_class\": {\"enum\": [\"D0\",\"D1\",\"D2\",\"D3\",\"D4\"]},\n    \"tool\": {\"type\": \"string\", \"minLength\": 1},\n    \"target\": {\"$ref\": \"#/$defs/hash\"},\n    \"pre_state_digest\": {\"$ref\": \"#/$defs/hash\"},\n    \"requested_action_digest\": {\"$ref\": \"#/$defs/hash\"},\n    \"result_digest\": {\"$ref\": \"#/$defs/hash\"},\n    \"post_state_digest\": {\"$ref\": \"#/$defs/hash\"},\n    \"parent_receipt\": {\"$ref\": \"#/$defs/hash\"},\n    \"sequence\": {\"type\": \"integer\", \"minimum\": 0},\n    \"outcome\": {\"enum\": [\"SUCCEEDED\",\"DENIED\",\"FAILED\",\"ROLLED_BACK\"]},\n    \"denial_code\": {\"type\": \"string\", \"minLength\": 1}\n  },\n  \"$defs\": {\"hash\": {\"type\": \"string\", \"pattern\": \"^[0-9a-f]{64}$\"}}\n}\n"),
